"""
Pytest tests for FHIR Observation ingest via registered/unregistered devices.

Requirement: A registered device shall push Observations via FHIR ingest;
             unregistered devices shall be rejected.
"""

import uuid
from datetime import datetime, timezone
from unittest.mock import MagicMock, patch

import pytest


# ---------------------------------------------------------------------------
# Helpers / Fixtures
# ---------------------------------------------------------------------------

FHIR_BASE_URL = "https://fhir.example.com/R4"
INGEST_ENDPOINT = f"{FHIR_BASE_URL}/Observation"

REGISTERED_DEVICE_ID = "device-001"
REGISTERED_DEVICE_TOKEN = "valid-token-abc123"

UNREGISTERED_DEVICE_ID = "device-999"
UNREGISTERED_DEVICE_TOKEN = "invalid-token-xyz"


def build_observation_payload(
    device_id: str,
    patient_id: str = "patient-123",
    value: float = 98.6,
    unit: str = "degF",
    loinc_code: str = "8310-5",
    loinc_display: str = "Body temperature",
) -> dict:
    """Return a minimal FHIR R4 Observation resource."""
    return {
        "resourceType": "Observation",
        "id": str(uuid.uuid4()),
        "status": "final",
        "category": [
            {
                "coding": [
                    {
                        "system": "http://terminology.hl7.org/CodeSystem/observation-category",
                        "code": "vital-signs",
                        "display": "Vital Signs",
                    }
                ]
            }
        ],
        "code": {
            "coding": [
                {
                    "system": "http://loinc.org",
                    "code": loinc_code,
                    "display": loinc_display,
                }
            ]
        },
        "subject": {"reference": f"Patient/{patient_id}"},
        "effectiveDateTime": datetime.now(timezone.utc).isoformat(),
        "device": {"reference": f"Device/{device_id}"},
        "valueQuantity": {
            "value": value,
            "unit": unit,
            "system": "http://unitsofmeasure.org",
            "code": unit,
        },
    }


class FHIRIngestClient:
    """
    Thin wrapper around the FHIR ingest service (production code under test).
    Replace the body of each method with real HTTP/SDK calls; the interface
    must remain stable so the tests never change.
    """

    def __init__(self, base_url: str, device_id: str, device_token: str):
        self.base_url = base_url
        self.device_id = device_id
        self.device_token = device_token
        self._session = None  # would be requests.Session() in production

    def push_observation(self, payload: dict) -> dict:
        """
        POST an Observation to the FHIR ingest endpoint.

        Returns a dict with keys:
          - status_code (int)
          - body        (dict | None)
        """
        raise NotImplementedError  # replaced by mock in tests


# ---------------------------------------------------------------------------
# Fixtures
# ---------------------------------------------------------------------------

@pytest.fixture()
def registered_client():
    """FHIR ingest client whose device token the server will accept."""
    return FHIRIngestClient(
        base_url=FHIR_BASE_URL,
        device_id=REGISTERED_DEVICE_ID,
        device_token=REGISTERED_DEVICE_TOKEN,
    )


@pytest.fixture()
def unregistered_client():
    """FHIR ingest client whose device token the server will reject."""
    return FHIRIngestClient(
        base_url=FHIR_BASE_URL,
        device_id=UNREGISTERED_DEVICE_ID,
        device_token=UNREGISTERED_DEVICE_TOKEN,
    )


@pytest.fixture()
def valid_observation():
    return build_observation_payload(device_id=REGISTERED_DEVICE_ID)


@pytest.fixture()
def observation_from_unregistered_device():
    return build_observation_payload(device_id=UNREGISTERED_DEVICE_ID)


# ---------------------------------------------------------------------------
# Shared mock responses
# ---------------------------------------------------------------------------

SUCCESS_RESPONSE = {
    "status_code": 201,
    "body": {
        "resourceType": "Observation",
        "id": "obs-server-001",
        "status": "final",
    },
}

UNAUTHORIZED_RESPONSE = {
    "status_code": 401,
    "body": {
        "resourceType": "OperationOutcome",
        "issue": [
            {
                "severity": "error",
                "code": "security",
                "diagnostics": "Device not registered or token invalid.",
            }
        ],
    },
}

FORBIDDEN_RESPONSE = {
    "status_code": 403,
    "body": {
        "resourceType": "OperationOutcome",
        "issue": [
            {
                "severity": "error",
                "code": "forbidden",
                "diagnostics": "Device is not authorised to push Observations.",
            }
        ],
    },
}


# ---------------------------------------------------------------------------
# 1. Registered Device – Positive Tests
# ---------------------------------------------------------------------------

class TestRegisteredDevicePushObservation:
    """Registered devices MUST be able to push Observations successfully."""

    def test_push_returns_201_created(self, registered_client, valid_observation):
        """Server accepts the Observation and returns HTTP 201."""
        with patch.object(
            registered_client, "push_observation", return_value=SUCCESS_RESPONSE
        ):
            response = registered_client.push_observation(valid_observation)

        assert response["status_code"] == 201, (
            f"Expected 201 Created, got {response['status_code']}"
        )

    def test_push_response_contains_observation_resource(
        self, registered_client, valid_observation
    ):
        """Response body must be an Observation resource."""
        with patch.object(
            registered_client, "push_observation", return_value=SUCCESS_RESPONSE
        ):
            response = registered_client.push_observation(valid_observation)

        assert response["body"]["resourceType"] == "Observation"

    def test_push_response_contains_server_assigned_id(
        self, registered_client, valid_observation
    ):
        """Server must assign and return a resource ID."""
        with patch.object(
            registered_client, "push_observation", return_value=SUCCESS_RESPONSE
        ):
            response = registered_client.push_observation(valid_observation)

        assert "id" in response["body"], "Server must return a resource ID"
        assert response["body"]["id"], "Server-assigned ID must not be empty"

    def test_push_preserves_observation_status(
        self, registered_client, valid_observation
    ):
        """Returned Observation must preserve the submitted status."""
        with patch.object(
            registered_client, "push_observation", return_value=SUCCESS_RESPONSE
        ):
            response = registered_client.push_observation(valid_observation)

        assert response["body"]["status"] == valid_observation["status"]

    def test_push_multiple_observations_sequentially(self, registered_client):
        """Registered device can push multiple Observations in sequence."""
        observations = [
            build_observation_payload(REGISTERED_DEVICE_ID, value=v)
            for v in [97.8, 98.2, 99.1]
        ]

        side_effects = [
            {**SUCCESS_RESPONSE, "body": {**SUCCESS_RESPONSE["body"], "id": f"obs-{i}"}}
            for i in range(len(observations))
        ]

        with patch.object(
            registered_client, "push_observation", side_effect=side_effects
        ):
            responses = [
                registered_client.push_observation(obs) for obs in observations
            ]

        assert all(r["status_code"] == 201 for r in responses), (
            "All sequential pushes by a registered device should succeed"
        )

    @pytest.mark.parametrize(
        "loinc_code, loinc_display, value, unit",
        [
            ("8310-5", "Body temperature", 98.6, "degF"),
            ("8867-4", "Heart rate", 72.0, "/min"),
            ("59408-5", "Oxygen saturation", 98.0, "%"),
            ("55284-4", "Blood pressure systolic & diastolic", 120.0, "mm[Hg]"),
            ("29463-7", "Body weight", 70.5, "kg"),
        ],
    )
    def test_push_various_vital_sign_observation_types(
        self,
        registered_client,
        loinc_code,
        loinc_display,
        value,
        unit,
    ):
        """Registered device can push different vital-sign Observation types."""
        payload = build_observation_payload(
            REGISTERED_DEVICE_ID,
            loinc_code=loinc_code,
            loinc_display=loinc_display,
            value=value,
            unit=unit,
        )
        with patch.object(
            registered_client, "push_observation", return_value=SUCCESS_RESPONSE
        ):
            response = registered_client.push_observation(payload)

        assert response["status_code"] == 201

    def test_push_invokes_correct_endpoint(self, registered_client, valid_observation):
        """push_observation must call the right FHIR endpoint."""
        with patch.object(
            registered_client, "push_observation", return_value=SUCCESS_RESPONSE
        ) as mock_push:
            registered_client.push_observation(valid_observation)

        mock_push.assert_called_once_with(valid_observation)

    def test_push_with_future_effective_datetime(self, registered_client):
        """Observations with a timestamp in the near future are still accepted."""
        payload = build_observation_payload(REGISTERED_DEVICE_ID)
        payload["effectiveDateTime"] = "2099-01-01T00:00:00+00:00"

        with patch.object(
            registered_client, "push_observation", return_value=SUCCESS_RESPONSE
        ):
            response = registered_client.push_observation(payload)

        assert response["status_code"] == 201


# ---------------------------------------------------------------------------
# 2. Unregistered Device – Negative Tests
# ---------------------------------------------------------------------------

class TestUnregisteredDeviceRejected:
    """Unregistered devices MUST be rejected when attempting to push Observations."""

    def test_push_returns_4xx_for_unregistered_device(
        self, unregistered_client, observation_from_unregistered_device
    ):
        """Any 4xx response confirms the device was rejected."""
        with patch.object(
            unregistered_client,
            "push_observation",
            return_value=UNAUTHORIZED_RESPONSE,
        ):
            response = unregistered_client.push_observation(
                observation_from_unregistered_device
            )

        assert 400 <= response["status_code"] < 500, (
            f"Expected a 4xx rejection, got {response['status_code']}"
        )

    def test_push_returns_401_for_invalid_token(
        self, unregistered_client, observation_from_unregistered_device
    ):
        """Server returns 401 Unauthorized when the device token is invalid."""
        with patch.object(
            unregistered_client,
            "push_observation",
            return_value=UNAUTHORIZED_RESPONSE,
        ):
            response = unregistered_client.push_observation(
                observation_from_unregistered_device
            )

        assert response["status_code"] == 401

    def test_push_returns_operation_outcome_for_unregistered_device(
        self, unregistered_client, observation_from_unregistered_device
    ):
        """Response body must be a FHIR OperationOutcome (not an Observation)."""
        with patch.object(
            unregistered_client,
            "push_observation",
            return_value=UNAUTHORIZED_RESPONSE,
        ):
            response = unregistered_client.push_observation(
                observation_from_unregistered_device
            )

        assert response["body"]["resourceType"] == "OperationOutcome", (
            "Rejection response must be a FHIR OperationOutcome"
        )

    def test_push_operation_outcome_contains_error_issue(
        self, unregistered_client, observation_from_unregistered_device
    ):
        """OperationOutcome must contain at least one issue with severity 'error'."""
        with patch.object(
            unregistered_client,
            "push_observation",
            return_value=UNAUTHORIZED_RESPONSE,
        ):
            response = unregistered_client.push_observation(
                observation_from_unregistered_device
            )

        issues = response["body"].get("issue", [])
        assert any(issue["severity"] == "error" for issue in issues), (
            "OperationOutcome must have at least one error-level issue"
        )

    def test_push_does_not_return_201_for_unregistered_device(
        self, unregistered_client, observation_from_unregistered_device
    ):
        """Unregistered device must NOT receive a 201 Created."""
        with patch.object(
            unregistered_client,
            "push_observation",
            return_value=UNAUTHORIZED_RESPONSE,
        ):
            response = unregistered_client.push_observation(
                observation_from_unregistered_device
            )

        assert response["status_code"] != 201, (
            "An unregistered device must not receive 201 Created"
        )

    def test_push_returns_403_for_known_but_unauthorised_device(self):
        """
        A device whose ID exists but lacks authorisation should get 403 Forbidden.
        (Known device, insufficient permissions.)
        """
        partially_known_client = FHIRIngestClient(
            base_url=FHIR_BASE_URL,
            device_id="device-known-no-perms",
            device_token="token-known-no-perms",
        )
        payload = build_observation_payload("device-known-no-perms")

        with patch.object(
            partially_known_client, "push_observation", return_value=FORBIDDEN_RESPONSE
        ):
            response = partially_known_client.push_observation(payload)

        assert response["status_code"] == 403

    def test_push_with_empty_token_is_rejected(self):
        """A device with an empty token string must be rejected."""
        no_token_client = FHIRIngestClient(
            base_url=FHIR_BASE_URL,
            device_id=UNREGISTERED_DEVICE_ID,
            device_token="",
        )
        payload = build_observation_payload(UNREGISTERED_DEVICE_ID)

        with patch.object(
            no_token_client, "push_observation", return_value=UNAUTHORIZED_RESPONSE
        ):
            response = no_token_client.push_observation(payload)

        assert response["status_code"] in (401, 403)

    def test_push_with_malformed_token_is_rejected(self):
        """A device with a syntactically malformed token must be rejected."""
        bad_token_client = FHIRIngestClient(
            base_url=FHIR_BASE_URL,
            device_id=UNREGISTERED_DEVICE_ID,
            device_token="!!!BAD-TOKEN!!!",
        )
        payload = build_observation_payload(UNREGISTERED_DEVICE_ID)

        with patch.object(
            bad_token_client, "push_observation", return_value=UNAUTHORIZED_RESPONSE
        ):
            response = bad_token_client.push_observation(payload)

        assert response["status_code"] in (400, 401, 403)

    @pytest.mark.parametrize("http_method_response", [UNAUTHORIZED_RESPONSE])
    def test_repeated_pushes_from_unregistered_device_always_rejected(
        self, unregistered_client, observation_from_unregistered_device, http_method_response
    ):
        """Repeated attempts from an unregistered device are always rejected."""
        with patch.object(
            unregistered_client,
            "push_observation",
            return_value=http_method_response,
        ):
            for _ in range(3):
                response = unregistered_client.push_observation(
                    observation_from_unregistered_device
                )
                assert response["status_code"] != 201, (
                    "Unregistered device must be rejected on every attempt"
                )


# ---------------------------------------------------------------------------
# 3. Boundary / Edge Cases
# ---------------------------------------------------------------------------

class TestObservationIngestEdgeCases:
    """Edge-case and boundary tests covering the registration boundary."""

    def test_registered_device_with_revoked_token_is_rejected(self):
        """A previously registered device whose token was revoked must be rejected."""
        revoked_client = FHIRIngestClient(
            base_url=FHIR_BASE_URL,
            device_id=REGISTERED_DEVICE_ID,
            device_token="revoked-token",
        )
        payload = build_observation_payload(REGISTERED_DEVICE_ID)

        with patch.object(
            revoked_client, "push_observation", return_value=UNAUTHORIZED_RESPONSE
        ):
            response = revoked_client.push_observation(payload)

        assert response["status_code"] in (401, 403)

    def test_observation_missing_device_reference_is_rejected(self, registered_client):
        """An Observation payload with no device reference should be rejected."""
        payload = build_observation_payload(REGISTERED_DEVICE_ID)
        del payload["device"]  # remove device reference

        rejected_response = {
            "status_code": 422,
            "body": {
                "resourceType": "OperationOutcome",
                "issue": [
                    {
                        "severity": "error",
                        "code": "required",
                        "diagnostics": "Device reference is required.",
                    }
                ],
            },
        }

        with patch.object(
            registered_client, "push_observation", return_value=rejected_response
        ):
            response = registered_client.push_observation(payload)

        assert response["status_code"] == 422
        assert response["body"]["resourceType"] == "OperationOutcome"

    def test_observation_with_mismatched_device_id_is_rejected(self, registered_client):
        """
        Observation that references a *different* unregistered device
        than the authenticated client's device should be rejected.
        """
        payload = build_observation_payload(device_id=UNREGISTERED_DEVICE_ID)

        with patch.object(
            registered_client, "push_observation", return_value=FORBIDDEN_RESPONSE
        ):
            response = registered_client.push_observation(payload)

        assert response["status_code"] in (401, 403, 422)

    def test_push_returns_correct_content_type_on_success(
        self, registered_client, valid_observation
    ):
        """Successful response should indicate FHIR JSON content type."""
        success_with_headers = {
            **SUCCESS_RESPONSE,
            "headers": {"Content-Type": "application/fhir+json; charset=utf-8"},
        }

        with patch.object(
            registered_client, "push_observation", return_value=success_with_headers
        ):
            response = registered_client.push_observation(valid_observation)

        content_type = response.get("headers", {}).get("Content-Type", "")
        assert "fhir+json" in content_type or response["status_code"] == 201, (
            "Successful ingest must use FHIR JSON content type"
        )

    def test_concurrent_pushes_from_registered_device_all_succeed(
        self, registered_client
    ):
        """Simulate concurrent pushes; all should succeed for a registered device."""
        import concurrent.futures

        observations = [
            build_observation_payload(REGISTERED_DEVICE_ID, value=float(i))
            for i in range(5)
        ]
        mock_responses = [
            {**SUCCESS_RESPONSE, "body": {**SUCCESS_RESPONSE["body"], "id": f"obs-{i}"}}
            for i in range(5)
        ]

        with patch.object(
            registered_client,
            "push_observation",
            side_effect=mock_responses,
        ):
            with concurrent.futures.ThreadPoolExecutor(max_workers=5) as executor:
                futures = [
                    executor.submit(registered_client.push_observation, obs)
                    for obs in observations
                ]
                results = [f.result() for f in concurrent.futures.as_completed(futures)]

        assert all(r["status_code"] == 201 for r in results), (
            "All concurrent pushes from a registered device must succeed"
        )

    def test_empty_observation_body_is_rejected(self, registered_client):
        """An empty payload must not be accepted by the ingest endpoint."""
        bad_response = {
            "status_code": 400,
            "body": {
                "resourceType": "OperationOutcome",
                "issue": [
                    {"severity": "error", "code": "invalid", "diagnostics": "Empty body"}
                ],
            },
        }

        with patch.object(
            registered_client, "push_observation", return_value=bad_response
        ):
            response = registered_client.push_observation({})

        assert response["status_code"] == 400

    def test_non_observation_resource_type_rejected(self, registered_client):
        """Sending a non-Observation resource type to the Observation endpoint is rejected."""
        wrong_resource = {
            "resourceType": "Patient",
            "id": "patient-999",
        }
        bad_response = {
            "status_code": 422,
            "body": {
                "resourceType": "OperationOutcome",
                "issue": [
                    {
                        "severity": "error",
                        "code": "invalid",
                        "diagnostics": "Expected resourceType Observation.",
                    }
                ],
            },
        }

        with patch.object(
            registered_client, "push_observation", return_value=bad_response
        ):
            response = registered_client.push_observation(wrong_resource)

        assert response["status_code"] == 422
